from flask import Flask, request, make_response
from werkzeug.security import generate_password_hash
import json

app = Flask(__name__)

@app.route('/updateProfile', methods=['POST'])
def updateProfile():
    data = request.get_json() # get incoming JSON object
    
    email = data.get('email') 
    password = data.get('password')
    twoFa = data.get('2FA')

    # Assuming user is already logged in and their profile info can be accessed from the session, for example:
    # current_user = session['username']   # Get current user's username from the session
    
    if not email or not password or twoFa is None: 
        return make_response(json.dumps({"error": "All fields are required."}), 400)
        
    try:
        hashed_password = generate_password_hash(password, method='sha256') # Hashing the password
        
        # Assuming we have a database and User model which can update the user profile. For example:
        # User.objects.get(username=current_user).update(email=email, password=hashed_password, twoFa=twoFa)
    
    except Exception as e: 
        return make_response(json.dumps({"error": "An error occurred while updating profile."}), 500)
        
    return make_response(json.dumps({"message": "Profile updated successfully."}), 200)

if __name__ == '__main__':
    app.run()